import{_ as e,o as a,c as s,ag as r}from"./chunks/framework.OsDJF_Ea.js";const d="/docs/modules/diffuser.png",c=JSON.parse('{"title":"Diffuser","description":"","frontmatter":{},"headers":[],"relativePath":"modules/diffuser.md","filePath":"modules/diffuser.md"}'),o={name:"modules/diffuser.md"};function i(l,t,n,u,h,f){return a(),s("div",null,[...t[0]||(t[0]=[r('<h1 id="diffuser" tabindex="-1">Diffuser <a class="header-anchor" href="#diffuser" aria-label="Permalink to &quot;Diffuser&quot;">​</a></h1><p><strong>Category:</strong> Effects</p><p>A lightweight reverb alternative using 4 serial allpass filters with feedback recirculation and a damping lowpass in the feedback path. Produces diffuse washes and spatial smearing without the CPU cost of a full reverb. Prime-number delay lengths prevent metallic ringing.</p><img src="'+d+'" alt="diffuser module"><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>inL</strong> (audio)</td><td>Left audio input.</td></tr><tr><td><strong>inR</strong> (audio)</td><td>Right audio input.</td></tr><tr><td><strong>mix</strong></td><td>Dry/wet blend 0-1. Default 0.3.</td></tr><tr><td><strong>size</strong></td><td>Scales all 4 allpass delay lengths. 0 = short/metallic (~1ms delays), 1 = long/hall (~50ms delays). Default 0.5.</td></tr><tr><td><strong>feedback</strong></td><td>Recirculation amount 0-1. 0 = single pass (subtle smear), 1 = long wash. Default 0.3.</td></tr><tr><td><strong>damp</strong></td><td>One-pole lowpass in feedback path. 0 = bright, 1 = dark tails. Default 0.3.</td></tr><tr><td><strong>modulate</strong></td><td>Internal LFO modulation depth 0-1. Wobbles the allpass delay lengths for chorus-like shimmer. 0 = static, 1 = full wobble. Default 0.</td></tr></tbody></table><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>outL</strong> (audio)</td><td>Left processed audio.</td></tr><tr><td><strong>outR</strong> (audio)</td><td>Right processed audio.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><p>Use at low mix (0.1-0.3) with moderate size for subtle space on any source. Crank feedback and size for ambient washes. Modulate size with a slow LFO for shimmering textures. Chain after Delay for lush echoes. At size=0 with high feedback, creates metallic resonances.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2>',11)])])}const m=e(o,[["render",i]]);export{c as __pageData,m as default};
